#include<cstdio>
#include<algorithm>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=1e5+10,W=1e9;int a[N],P[N],p,mx[N<<2],idx[N],n,Q,ans[N*3];
typedef std::pair<int,int> pii;std::vector<pii> Qy[N];int t[N];
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline int und(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]>=k?r=m-1:l=m+1;return r+1;}
inline void build(int l=0,int r=p+1,int cur=1)
{
	if(l==r)return idx[l]=cur,void();int mid=(l+r)>>1;
	build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);
}
inline void mdy(int pos,int w){int x=idx[pos];mx[x]=w;while(x>>1){mx[x=x>>1]=w;}}
inline int qry(int ql,int qr,int l=0,int r=p+1,int cur=1)
{
	if(ql>qr)return 0;if(ql==l&&r==qr)return mx[cur];int mid=(l+r)>>1;
	if(qr<=mid)return qry(ql,qr,l,mid,cur<<1);if(ql>mid)return qry(ql,qr,mid+1,r,cur<<1|1);
	return max(qry(ql,mid,l,mid,cur<<1),qry(mid+1,qr,mid+1,r,cur<<1|1));
}
inline void Mdy(int x,int w){x=n-x+1;while(x<=n)t[x]=min(t[x],w),x+=(x&-x);}
inline int Qry(int x){x=n-x+1;int r=t[x];while(x)r=min(r,t[x]),x^=(x&-x);return r;}
int main()
{
	n=read();Q=read();rep(1,n,i)P[i]=a[i]=read();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;
	rep(1,Q,i){int l=read(),r=read();Qy[r].push_back({l,i});}
	memset(t,0x3f,(n+3)*sizeof(t[0]));build();
	int ql,qr;mdy(bnd(a[1]),1);rep(2,n,i)
	{
		ql=0;qr=a[i]-1;while(ql<=qr)
		{
			int x=qry(und(ql),bnd(qr));if(!x)break;
			Mdy(x,a[i]-a[x]);if(ql==qr)break;ql=(ql+qr+1)>>1;
			
		}
		ql=a[i]+1;qr=W;while(ql<=qr)
		{
			int x=qry(und(ql),bnd(qr));if(!x)break;
			Mdy(x,a[x]-a[i]);if(ql==qr)break;qr=(ql+qr)>>1;
		}
		for(pii w:Qy[i]){ans[w.second]=Qry(w.first);}
		mdy(bnd(a[i]),i);
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
